    100% {margin-left:0;}
}
.fccp-progress{{{num|1}}} {
	height:3px;
	animation-name: fccp-progress{{{num|1}}};
	animation-delay: 0s;
	animation-timing-function: linear;
	animation-duration: 18s;
	animation-iteration-count:1;
	animation-fill-mode:both;
	animation-direction:normal;
}
@keyframes fccp-progressed{{{num|1}}} {
    0% {opacity:1;}
    100% {opacity:0;}
}
.fccp-progressed{{{num|1}}} {
	animation-name: fccp-progressed{{{num|1}}};
	animation-delay: 19.99s;
	animation-timing-function: linear;
	animation-duration: 0s;
	animation-iteration-count:1;
	animation-fill-mode:both;
	animation-direction:normal;
}
